import{_ as e}from"./chunks/Brainsucker__485._FXlVM3k.js";import{c as d,Q as s,j as r,m as a}from"./chunks/framework.BPKcPtvA.js";const b=JSON.parse('{"title":"吸脑者事件 / Brainsucker","description":"特殊牌组事件。它会生成喜欢/讨厌的卡牌条件，引导你从牌组里交出符合偏好的牌。","frontmatter":{"title":"吸脑者事件 / Brainsucker","description":"特殊牌组事件。它会生成喜欢/讨厌的卡牌条件，引导你从牌组里交出符合偏好的牌。"},"headers":[],"relativePath":"buildings/brainsucker.md","filePath":"buildings/brainsucker.md"}'),i={name:"buildings/brainsucker.md"};function n(c,t,o,l,h,p){return s(),r("div",null,[...t[0]||(t[0]=[a('<section class="dq-profession-hero dq-feature-hero"><div><p class="dq-kicker">Dungeon Feature · 事件</p><h1>吸脑者事件</h1><p class="dq-lede">特殊牌组事件。它会生成喜欢/讨厌的卡牌条件，引导你从牌组里交出符合偏好的牌。</p><p class="dq-original">原名：Brainsucker · 类名：Brainsucker</p><div class="dq-tag-row"><span>事件</span><span>AddWeirdFeature 中占 15%。</span></div></div><div class="dq-profession-portrait dq-feature-portrait"><img src="'+e+'" alt="Brainsucker" loading="lazy"></div></section><section class="dq-wide-panel"><h2>Metadata</h2><div class="dq-meta-grid"><span title="wiki 中使用的中文名称。"><strong>中文名</strong><em>吸脑者事件</em></span><span title="游戏原始名称或代码中对应名称。"><strong>英文名</strong><em>Brainsucker</em></span><span title="反编译类型或创建 feature 时使用的内部名称。"><strong>类名</strong><em>Brainsucker</em></span><span title="用于图鉴分组。"><strong>类别</strong><em>事件</em></span><span title="从地牢生成和奖励分配中恢复出的生成入口。"><strong>生成方式</strong><em>AddWeirdFeature 中占 15%。</em></span></div></section><section class="dq-section-block"><h2>机制说明</h2><div class="dq-mechanic-list"><p>AddWeirdFeature 的随机数大于等于 0.85 时生成 Brainsucker。</p><p>Brainsucker 字段包含 usesLeft、internalName、like1、like2、dislike1；Initialize 把 usesLeft 设为 3，然后 GeneratePreferences。</p><p>偏好类型来自 BrainsuckerCardProperty：牌名开头、牌名包含、卡牌类型、是否可升级。</p><p>交互会进入 ConstructDeckViewer / DeckButtons，玩家选择牌并确认后 usesLeft 减 1，由 BrainsuckResolve(c) 结算。</p></div></section><section class="dq-section-block"><h2>偏好生成</h2><table class="dq-data-table"><thead><tr><th>位置</th><th>规则</th></tr></thead><tbody><tr><td>like1</td><td>先生成 1 个喜欢条件。25% 概率固定为 LEVELABLE；否则从牌名开头、牌名包含、卡牌类型里生成。</td></tr><tr><td>like2</td><td>再生成 1 个喜欢条件；在牌名开头和牌名包含之间随机。</td></tr><tr><td>dislike1</td><td>生成 1 个讨厌条件；在牌名开头和牌名包含之间随机，并标记为负向条件。</td></tr><tr><td>顺序</td><td>三个条件生成后会洗牌，再写回 like1、like2、dislike1；最后强制最后一个条件为 dislike。</td></tr></tbody></table></section><section class="dq-section-block"><h2>结算</h2><table class="dq-data-table"><thead><tr><th>步骤</th><th>实际含义</th></tr></thead><tbody><tr><td>选牌</td><td>Dr. Hillditi 会打开你的牌组，提示 Choose a card to give Dr. Hillditi。你确认后，这张牌会从 DungeonPlayer.deck 中移除。</td></tr><tr><td>先看牌本身</td><td>被交出的牌先使用自己的 metadata tier 作为基础。比如 Fireball 是 3 阶，Accelerate 是 10 阶，Slap（内部名 Strike）是 1 阶。</td></tr><tr><td>再看偏好</td><td>它把这张牌拿去对照招牌上的 2 个 Likes 和 1 个 Dislikes。命中喜欢条件会把结果往上推；命中讨厌条件会把结果往下压；完全不合口味时也会吃一个基础惩罚。</td></tr><tr><td>决定奖励阶级</td><td>调整后的结果大于 0 时，才会用这个阶级调用 CardFinder.ChooseReward 抽一张新牌；超过 10 阶会按 10 阶处理。</td></tr><tr><td>坏结果</td><td>如果调整后掉到 0 或更低，就不会抽奖励牌，而是按 Curse 处理。</td></tr><tr><td>卡牌出现权重门槛</td><td>偏好结果达到 2 或更高时，奖励抽卡会使用更高的职业权重门槛（内部 minAffinity 5）；否则使用较低门槛（minAffinity 1）。</td></tr><tr><td>次数</td><td>每个 Brainsucker 初始可处理 3 张牌。usesLeft 仍大于 0 时显示 Again! (N Left)，可以继续交牌；用完后事件结束。</td></tr></tbody></table></section><section class="dq-section-block"><h2>结算例子</h2><p class="dq-note">下面的偏好组合是示例，用来说明同一张牌为什么会换到不同质量的奖励。</p><table class="dq-data-table"><thead><tr><th>交出的牌</th><th>当次招牌</th><th>结果</th></tr></thead><tbody><tr><td>Fireball（3 阶 SpellCard）</td><td>Likes: Spell cards；Cards whose names contain &#39;ball&#39;。Dislikes: Cards whose names start with &#39;F&#39;。</td><td>Fireball 同时命中 2 个喜欢条件和 1 个讨厌条件。奖励会围绕 3 阶向上或向下调整，而不是固定返还 3 阶牌。</td></tr><tr><td>Accelerate（10 阶 ActionCard）</td><td>Likes: Action cards；Cards whose names start with &#39;A&#39;。没有命中讨厌条件。</td><td>基础已经是 10 阶，再命中喜欢条件也不会超过上限；奖励仍按最高的 10 阶抽取。</td></tr><tr><td>Slap（内部名 Strike，1 阶 ActionCard）</td><td>没有命中喜欢条件，并且命中 Dislikes。</td><td>低阶牌再吃到负向修正时，结果会掉到 0 或更低；这条分支不会抽奖励牌，会变成 Curse。</td></tr></tbody></table></section><section class="dq-section-block"><h2>偏好规则</h2><p class="dq-note">Brainsucker 会生成两个喜欢条件和一个讨厌条件。你从牌组里选择卡牌交给它，结算会读取这些偏好。</p><table class="dq-data-table"><thead><tr><th>偏好类型</th><th>含义</th></tr></thead><tbody><tr><td><code>NAME_STARTS_WITH</code></td><td>喜欢或讨厌牌名以某段文本开头的牌。</td></tr><tr><td><code>NAME_CONTAINS</code></td><td>喜欢或讨厌牌名包含某段文本的牌。</td></tr><tr><td><code>CARD_TYPE</code></td><td>喜欢或讨厌某种卡牌类型。</td></tr><tr><td><code>LEVELABLE</code></td><td>喜欢或讨厌可升级牌。</td></tr></tbody></table></section><section class="dq-section-block"><h2>随机奖励权重</h2><table class="dq-data-table"><thead><tr><th>楼层组</th><th>概率</th><th>说明</th></tr></thead><tbody><tr><td>特殊建筑</td><td>15%</td><td>AddWeirdFeature 中随机数大于等于 0.85。</td></tr></tbody></table></section><section class="dq-action-row"><a class="dq-button" href="/buildings">回到地牢建筑图鉴</a><a class="dq-button dq-button-secondary" href="/mechanics/dungeon-generation">查看地牢生成</a></section>',9)])])}const m=d(i,[["render",n]]);export{b as __pageData,m as default};
